import type { RouteMiddleware } from "rwsdk/router";

const LOG_FILE = "/home/user/myproject/logs/access.log";
const LOG_DIR = "/home/user/myproject/logs";

async function ensureLogDir(): Promise<void> {
  try {
    const fs = await import("node:fs/promises");
    await fs.mkdir(LOG_DIR, { recursive: true });
  } catch {
    // ignore — directory already exists or not writable
  }
}

async function appendLogLine(line: string): Promise<void> {
  try {
    const fs = await import("node:fs/promises");
    await fs.appendFile(LOG_FILE, line);
  } catch (err) {
    console.error("[requestLogger] failed to write log:", err);
  }
}

export const requestLogger: RouteMiddleware = async ({
  request,
  ctx,
  response,
}) => {
  const startMs = Date.now();

  // Generate UUID v4 using the platform-provided crypto global
  const requestId = crypto.randomUUID();

  // Attach to context so downstream handlers can read it
  ctx.requestId = requestId;

  // Set the response header immediately so it's present on every response,
  // including error responses and unmatched paths.
  response.headers.set("X-Request-Id", requestId);

  // We need to hook in *after* the response is ready. In RedwoodSDK the
  // middleware array is processed sequentially; we use a waitUntil-style
  // pattern by returning a Promise that first lets the chain continue via
  // a "pass-through" and then writes the log once the response status is
  // available.  Because defineApp resolves all middleware before sending,
  // we attach the logging work to the cf ExecutionContext so it doesn't
  // block the response but still completes before the worker terminates.
  //
  // However, to capture the final status code we need to run the log
  // write synchronously after the rest of the middleware/route chain
  // returns.  The simplest correct approach in RedwoodSDK is to *not*
  // return early here, let the framework continue, then log in a
  // microtask using `cf.waitUntil`.
  //
  // Because we cannot easily hook "after response" from a top-level
  // middleware in RedwoodSDK without wrapping the entire handler, we
  // schedule the log write via queueMicrotask so it fires after the
  // current synchronous request processing resolves but before the worker
  // context is torn down.  The status defaults to 200 and we read it from
  // the ResponseInit object that the framework has mutated.

  // Capture a reference to the ResponseInit object; the framework mutates
  // `response.status` and `response.headers` before sending.
  const responseInit = response;
  const url = new URL(request.url);
  const method = request.method.toUpperCase();
  const path = url.pathname;
  const userAgent = request.headers.get("User-Agent") ?? "";

  await ensureLogDir();

  // Schedule the log line to be written after this middleware function
  // returns.  By the time the microtask runs, the framework will have
  // populated `responseInit.status`.
  queueMicrotask(() => {
    const durationMs = Date.now() - startMs;
    const status =
      typeof responseInit.status === "number" ? responseInit.status : 200;
    const ts = new Date().toISOString();

    const logLine =
      JSON.stringify({
        ts,
        method,
        path,
        status,
        durationMs,
        requestId,
        userAgent,
      }) + "\n";

    // fire-and-forget; errors are swallowed inside appendLogLine
    void appendLogLine(logLine);
  });
};

